form:Form.form:Scripts:
		var RS;

function OnLoad()
{                
	RS=GetProxy().SQLService().GetXML(Ctrl("main").getResource("REPORTES"),'');
	EnableButtons();
}

function EnableButtons()
{      
	if (Ctrl("d_reporte").GetXValue()!="")         
	{ 
		if(RS.FindElement2("OPT","value",Ctrl("d_reporte").GetXValue()).GetAttr("impl")=="M")
		{
			Ctrl("l_eva2").SetEnabled(true);
			Ctrl("l_eva3").SetEnabled(true);
			Ctrl("l_pree").SetEnabled(true);
		} else
		{
			Ctrl("l_eva2").SetXValue("0"); Ctrl("l_eva2").SetEnabled(false);
			Ctrl("l_eva3").SetXValue("0"); Ctrl("l_eva3").SetEnabled(false);
			Ctrl("l_pree").SetXValue("0"); Ctrl("l_pree").SetEnabled(false);
		}
	} else
	{
		Ctrl("l_eva2").SetXValue("0"); Ctrl("l_eva2").SetEnabled(false);
		Ctrl("l_eva3").SetXValue("0"); Ctrl("l_eva3").SetEnabled(false);
		Ctrl("l_pree").SetXValue("0"); Ctrl("l_pree").SetEnabled(false);
	}                       
}
